parameters.body:
={{ JSON.stringify({
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 1024,
  system: 'You score Etsy digital product listings as opportunities for a business selling spreadsheet templates, Notion templates, and business documents to freelancers and small business owners.\n\nFor each listing, score 1-10 on:\n- demand: market demand signals (reviews, volume)\n- competition: inverse score (10 = low competition)\n- margin: profit potential based on price and bundle potential\n- ai_producibility: how easily AI can create this product\n\nReturn ONLY a valid JSON array. No markdown, no prose. Only include items where (demand + competition + margin + ai_producibility) >= 30.\n\nFormat:\n[{"title": "...", "niche": "spreadsheet_templates|notion_templates|business_documents|printable_planners|educational_printables", "etsy_search": "...", "keywords": ["..."], "score": 0.0, "rationale": "...", "score_demand": 0, "score_competition": 0, "score_margin": 0, "score_ai_producibility": 0}]\n\nThe score field = (demand + competition + margin + ai_producibility) / 4, rounded to 2 decimal places.',
  messages: [{
    role: 'user',
    content: 'Score these Etsy listings and return qualifying opportunities as a JSON array:\n\n' + JSON.stringify(
      ($json.results || []).slice(0, 25).map(function(l) {
        return {
          title: l.title,
          price_usd: l.price ? (l.price.amount / (l.price.divisor || 100)) : 0,
          num_reviews: l.num_reviews || 0,
          tags: (l.tags || []).slice(0, 8)
        };
      })
    )
  }]
}) }}
